## TanStack Query v5

```bash
npm install @tanstack/react-query
```

```tsx
// Provider setup
import { QueryClient, QueryClientProvider } from '@tanstack/react-query';
const queryClient = new QueryClient({
  defaultOptions: { queries: { staleTime: 60_000, retry: 1 } },
});

export function App() {
  return <QueryClientProvider client={queryClient}><Routes /></QueryClientProvider>;
}
```

### useQuery
```tsx
import { useQuery } from '@tanstack/react-query';

function UserProfile({ id }: { id: string }) {
  const { data, isLoading, error } = useQuery({
    queryKey: ['user', id],     // cache key — array form recommended
    queryFn: () => fetchUser(id),
    staleTime: 5 * 60_000,      // 5 min — don't refetch if fresh
    gcTime: 10 * 60_000,        // 10 min — keep unused data in cache (v5: gcTime not cacheTime)
  });
  if (isLoading) return <Skeleton />;
  if (error) return <ErrorBanner error={error} />;
  return <Profile user={data} />;
}
```

### useMutation + cache invalidation
```tsx
const { mutateAsync, isPending } = useMutation({
  mutationFn: (data: UpdateUserInput) => updateUser(id, data),
  onSuccess: () => queryClient.invalidateQueries({ queryKey: ['user', id] }),
  onError: (err) => toast.error(err.message),
});
```

**Key rules:**
- `queryKey` must include all variables the query depends on
- Prefer `invalidateQueries` over manual cache updates for correctness
- Set `staleTime` per-query based on how often data changes

## Zustand Store

```bash
npm install zustand
```

### Basic store (with immer + devtools)
```ts
import { create } from 'zustand';
import { immer } from 'zustand/middleware/immer';
import { devtools } from 'zustand/middleware';

interface CartStore {
  items: CartItem[];
  addItem: (item: CartItem) => void;
  removeItem: (id: string) => void;
  clear: () => void;
}

export const useCartStore = create<CartStore>()(devtools(immer((set) => ({
  items: [],
  addItem: (item) => set((state) => { state.items.push(item); }),  // immer: mutate draft
  removeItem: (id) => set((state) => { state.items = state.items.filter(i => i.id !== id); }),
  clear: () => set({ items: [] }),
}))));
```

### Slice pattern (large stores)
```ts
// slices/authSlice.ts
export const createAuthSlice = (set) => ({
  user: null as User | null,
  setUser: (user: User) => set({ user }),
  logout: () => set({ user: null }),
});

// store.ts — combine slices
const useStore = create<AuthSlice & UiSlice>()((...a) => ({
  ...createAuthSlice(...a),
  ...createUiSlice(...a),
}));
```

### Persistence
```ts
import { persist } from 'zustand/middleware';
export const usePrefsStore = create(persist(
  (set) => ({ theme: 'light', setTheme: (t) => set({ theme: t }) }),
  { name: 'user-prefs', partialize: (s) => ({ theme: s.theme }) }
));
```

**Rule:** Only store CLIENT state in Zustand. Server data belongs in TanStack Query.

## Jotai Atoms

```bash
npm install jotai
```

```ts
import { atom, useAtom, useAtomValue, useSetAtom } from 'jotai';
import { atomWithStorage } from 'jotai/utils';

// Primitive atom
const countAtom = atom(0);

// Derived (read-only) atom
const doubleAtom = atom((get) => get(countAtom) * 2);

// Writable derived atom
const incrementAtom = atom(
  null,
  (get, set) => set(countAtom, get(countAtom) + 1)
);

// Persist to localStorage
const themeAtom = atomWithStorage<'light' | 'dark'>('theme', 'light');
```

### Usage in components
```tsx
function Counter() {
  const [count, setCount] = useAtom(countAtom);
  const double = useAtomValue(doubleAtom);    // read-only subscription
  const increment = useSetAtom(incrementAtom); // write-only (no re-render on count change)
  return (
    <div>
      <p>{count} × 2 = {double}</p>
      <button onClick={increment}>+1</button>
    </div>
  );
}
```

### Async atom
```ts
const userAtom = atom(async (get) => {
  const id = get(userIdAtom);
  return fetchUser(id); // suspends automatically
});
// Use with <Suspense> boundary
```

**Jotai vs Zustand:** Use Jotai for highly granular, independent pieces of state where you want React's component model. Use Zustand for cohesive state slices with actions.

## State Classification Matrix

| State Type | Tool | Examples |
|-----------|------|----------|
| Server state | TanStack Query | Users, products, orders, any DB data |
| Client UI state | Zustand / Jotai | Sidebar open, modal state, selected items |
| Form state | React Hook Form | Field values, validation, dirty/touched |
| URL state | `useSearchParams` / `nuqs` | Filters, sort, pagination, active tab |
| Session/auth | Zustand + persist | Current user, token, preferences |

### Anti-pattern: server state in Zustand
```ts
// WRONG — duplicates server state, creates stale data bugs
const useUsersStore = create(() => ({
  users: [],
  fetchUsers: async () => { /* copies data into Zustand */ }
}));

// CORRECT — TanStack Query owns it
const { data: users } = useQuery({ queryKey: ['users'], queryFn: fetchUsers });
```

### URL state with nuqs (shareable, bookmarkable)
```ts
import { useQueryState } from 'nuqs';

function ProductList() {
  const [page, setPage]    = useQueryState('page', { defaultValue: '1' });
  const [search, setSearch] = useQueryState('q',    { defaultValue: '' });
  const [sort, setSort]    = useQueryState('sort',  { defaultValue: 'name' });
  // URL: /products?page=2&q=shirt&sort=price
}
```

**Rule:** Never copy server-fetched data into Zustand/Jotai. Always derive UI state from TanStack Query cache.

## Optimistic Updates

```ts
const queryClient = useQueryClient();

const { mutate: toggleLike } = useMutation({
  mutationFn: (postId: string) => likePost(postId),

  onMutate: async (postId) => {
    // 1. Cancel in-flight queries to avoid overwriting optimistic update
    await queryClient.cancelQueries({ queryKey: ['post', postId] });

    // 2. Snapshot current value for rollback
    const previous = queryClient.getQueryData<Post>(['post', postId]);

    // 3. Apply optimistic update
    queryClient.setQueryData<Post>(['post', postId], (old) =>
      old ? { ...old, likes: old.likes + 1, liked: true } : old
    );

    return { previous }; // context for rollback
  },

  onError: (_err, postId, ctx) => {
    // 4. Roll back on error
    if (ctx?.previous) {
      queryClient.setQueryData(['post', postId], ctx.previous);
    }
  },

  onSettled: (_data, _err, postId) => {
    // 5. Always refetch to sync with server truth
    queryClient.invalidateQueries({ queryKey: ['post', postId] });
  },
});
```

**Steps:** cancel → snapshot → apply → rollback on error → invalidate on settle

## TanStack Query + Next.js App Router SSR

```tsx
// app/products/page.tsx — Server Component
import { dehydrate, HydrationBoundary, QueryClient } from '@tanstack/react-query';

export default async function ProductsPage() {
  const queryClient = new QueryClient();

  await queryClient.prefetchQuery({
    queryKey: ['products'],
    queryFn: fetchProducts,
  });

  return (
    <HydrationBoundary state={dehydrate(queryClient)}>
      <ProductList />  {/* receives pre-populated cache */}
    </HydrationBoundary>
  );
}
```

```tsx
// components/ProductList.tsx — Client Component
'use client';
import { useQuery } from '@tanstack/react-query';

export function ProductList() {
  const { data } = useQuery({
    queryKey: ['products'],
    queryFn: fetchProducts,
    // No loading state — data already in cache from server!
  });
  return <ul>{data?.map(p => <li key={p.id}>{p.name}</li>)}</ul>;
}
```

**Why:** Eliminates network waterfall — user sees data immediately, no spinner on initial load.

## URL State with nuqs

```bash
npm install nuqs
```

```tsx
// app/products/page.tsx
import { createSearchParamsCache, parseAsString, parseAsInteger } from 'nuqs/server';

export const searchParamsCache = createSearchParamsCache({
  q:    parseAsString.withDefault(''),
  page: parseAsInteger.withDefault(1),
  sort: parseAsString.withDefault('name'),
});

export default function Page({ searchParams }) {
  const { q, page, sort } = searchParamsCache.parse(searchParams);
  return <ProductList query={q} page={page} sort={sort} />;
}
```

```tsx
// components/SearchBar.tsx — Client Component
'use client';
import { useQueryState } from 'nuqs';

export function SearchBar() {
  const [q, setQ] = useQueryState('q', {
    defaultValue: '',
    shallow: false,       // triggers server re-render on change
    throttleMs: 300,      // debounce URL updates
  });
  return <input value={q} onChange={e => setQ(e.target.value)} />;
}
```

**Benefit:** Filters survive page refresh, can be shared via URL, works with browser back/forward.

## Context Performance Patterns

### Problem: one context = all consumers re-render
```tsx
// BAD — every consumer re-renders on any value change
const AppContext = createContext({ user, theme, cart, setCart });
```

### Fix 1: Split contexts by update frequency
```tsx
const UserContext  = createContext<User | null>(null);  // changes rarely
const ThemeContext = createContext<Theme>('light');       // per-user
const CartContext  = createContext<CartState>({ ... });  // changes often
```

### Fix 2: Separate state from dispatch
```tsx
const CartStateContext   = createContext<CartItem[]>([]);
const CartDispatchContext = createContext<Dispatch<CartAction>>(() => {});

// Dispatch never changes — consumers using only dispatch never re-render
function AddToCartButton({ item }) {
  const dispatch = useContext(CartDispatchContext); // stable ref
  return <button onClick={() => dispatch({ type: 'add', item })}>Add</button>;
}
```

### Fix 3: Memoize context value
```tsx
function CartProvider({ children }) {
  const [items, dispatch] = useReducer(cartReducer, []);
  const value = useMemo(() => ({ items, dispatch }), [items]); // stable unless items changes
  return <CartContext.Provider value={value}>{children}</CartContext.Provider>;
}
```

**When context re-renders are OK:** Infrequently changing data (auth user, theme). For frequent updates, use Zustand/Jotai instead.
